queries.sphinxql:

drop table if exists t;


create table t(f text);
insert into t values(1, 'abc');
flush ramchunk t;
alter table t add column v float_vector knn_type='hnsw' knn_dims='4' hnsw_similarity='l2';
select * from t;
drop table t;


create table t(f text);
insert into t values(1, 'hello');
alter table t add column v float_vector knn_type='hnsw' hnsw_similarity='l2' model_name='sentence-transformers/all-MiniLM-L6-v2' from='f';
show create table t;
drop table t;


create table t(f text, s string);
